class HistoricalEventTracker:
    def __init__(self):
        self.events = {
            'birth': 'c. 1820s',
            'joined_Ogunmola_army': '1850s',
            'became_Aare_Ona_Kakanfo': '1871-10-03',
            'conversion_to_Islam': '1870s',
            'son_born_Sanusi': 'post_conversion',
            'death': '1885',
            'Kiriji_War_started': '1877',
            'Kiriji_War_ended': '1893'
        }

    def get_events(self):
        return self.events

# Example usage:
tracker = HistoricalEventTracker()
for event, date in tracker.get_events().items():
    print(f"{event.replace('_', ' ').title()}: {date}")
